import{_ as s,o as e,c as n,ae as t}from"./chunks/framework.C7FLYIpo.js";const u=JSON.parse('{"title":"Linux 앱","description":"Linux 지원 + 동반 앱 상태","frontmatter":{"title":"Linux 앱","description":"Linux 지원 + 동반 앱 상태"},"headers":[],"relativePath":"platforms/linux.md","filePath":"platforms/linux.md","lastUpdated":null}'),l={name:"platforms/linux.md"};function p(o,a,i,c,d,r){return e(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="linux-앱" tabindex="-1">Linux 앱 <a class="header-anchor" href="#linux-앱" aria-label="Permalink to &quot;Linux 앱&quot;">​</a></h1><p>게이트웨이는 Linux에서 완전히 지원됩니다. <strong>Node가 권장 런타임입니다</strong>. 게이트웨이에는 Bun을 권장하지 않습니다 (WhatsApp/Telegram 버그).</p><p>네이티브 Linux 동반 앱은 계획 중입니다. 빌드에 도움을 주고 싶다면 기여를 환영합니다.</p><h2 id="초보자-빠른-경로-vps" tabindex="-1">초보자 빠른 경로 (VPS) <a class="header-anchor" href="#초보자-빠른-경로-vps" aria-label="Permalink to &quot;초보자 빠른 경로 (VPS)&quot;">​</a></h2><ol><li>Node 24 설치 (권장; 호환성을 위해 현재 <code>22.14+</code>인 Node 22 LTS도 작동)</li><li><code>npm i -g openclaw@latest</code></li><li><code>openclaw onboard --install-daemon</code></li><li>노트북에서: <code>ssh -N -L 18789:127.0.0.1:18789 &lt;user&gt;@&lt;host&gt;</code></li><li><code>http://127.0.0.1:18789/</code>를 열고 구성된 공유 비밀로 인증합니다 (기본값 토큰; <code>gateway.auth.mode: &quot;password&quot;</code> 설정 시 비밀번호)</li></ol><p>전체 Linux 서버 가이드: <a href="/openclaw-docs-ko/vps">Linux 서버</a>. 단계별 VPS 예시: <a href="/openclaw-docs-ko/install/exe-dev">exe.dev</a></p><h2 id="설치" tabindex="-1">설치 <a class="header-anchor" href="#설치" aria-label="Permalink to &quot;설치&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/start/getting-started">시작하기</a></li><li><a href="/openclaw-docs-ko/install/updating">설치 및 업데이트</a></li><li>선택적 흐름: <a href="/openclaw-docs-ko/install/bun">Bun (실험적)</a>, <a href="/openclaw-docs-ko/install/nix">Nix</a>, <a href="/openclaw-docs-ko/install/docker">Docker</a></li></ul><h2 id="게이트웨이" tabindex="-1">게이트웨이 <a class="header-anchor" href="#게이트웨이" aria-label="Permalink to &quot;게이트웨이&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/gateway/">게이트웨이 런북</a></li><li><a href="/openclaw-docs-ko/gateway/configuration">구성</a></li></ul><h2 id="게이트웨이-서비스-설치-cli" tabindex="-1">게이트웨이 서비스 설치 (CLI) <a class="header-anchor" href="#게이트웨이-서비스-설치-cli" aria-label="Permalink to &quot;게이트웨이 서비스 설치 (CLI)&quot;">​</a></h2><p>다음 중 하나를 사용하십시오:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>openclaw onboard --install-daemon</span></span></code></pre></div><p>또는:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>openclaw gateway install</span></span></code></pre></div><p>또는:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>openclaw configure</span></span></code></pre></div><p>프롬프트가 표시되면 <strong>Gateway service</strong>를 선택합니다.</p><p>복구/마이그레이션:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>openclaw doctor</span></span></code></pre></div><h2 id="시스템-제어-systemd-사용자-유닛" tabindex="-1">시스템 제어 (systemd 사용자 유닛) <a class="header-anchor" href="#시스템-제어-systemd-사용자-유닛" aria-label="Permalink to &quot;시스템 제어 (systemd 사용자 유닛)&quot;">​</a></h2><p>OpenClaw는 기본적으로 systemd <strong>사용자</strong> 서비스를 설치합니다. 공유 또는 항상 켜져 있는 서버에는 <strong>시스템</strong> 서비스를 사용하십시오. <code>openclaw gateway install</code>과 <code>openclaw onboard --install-daemon</code>은 이미 현재 정규 유닛을 렌더링합니다. 사용자 지정 시스템/서비스 관리자 설정이 필요한 경우에만 수동으로 작성하십시오. 전체 서비스 지침은 <a href="/openclaw-docs-ko/gateway/">게이트웨이 런북</a>에 있습니다.</p><p>최소 설정:</p><p><code>~/.config/systemd/user/openclaw-gateway[-&lt;profile&gt;].service</code> 만들기:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Unit]</span></span>
<span class="line"><span>Description=OpenClaw Gateway (profile: &lt;profile&gt;, v&lt;version&gt;)</span></span>
<span class="line"><span>After=network-online.target</span></span>
<span class="line"><span>Wants=network-online.target</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Service]</span></span>
<span class="line"><span>ExecStart=/usr/local/bin/openclaw gateway --port 18789</span></span>
<span class="line"><span>Restart=always</span></span>
<span class="line"><span>RestartSec=5</span></span>
<span class="line"><span>TimeoutStopSec=30</span></span>
<span class="line"><span>TimeoutStartSec=30</span></span>
<span class="line"><span>SuccessExitStatus=0 143</span></span>
<span class="line"><span>KillMode=control-group</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Install]</span></span>
<span class="line"><span>WantedBy=default.target</span></span></code></pre></div><p>활성화:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>systemctl --user enable --now openclaw-gateway[-&lt;profile&gt;].service</span></span></code></pre></div>`,27)])])}const g=s(l,[["render",p]]);export{u as __pageData,g as default};
